mapper.select:
SELECT
FROM forum_topic t LEFT JOIN `user` u ON t.user_id = u.user_id LEFT JOIN book b ON t.book_id = b.book_id AND b.deleted = 0 LEFT JOIN `user` lu ON t.last_reply_user_id = lu.user_id WHERE t.deleted = 0
AND t.board_id = #{boardId}
AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.content LIKE CONCAT('%', #{keyword}, '%'))
AND t.book_id = #{bookId}
ORDER BY t.pinned DESC, COALESCE(t.last_reply_at, t.create_time) DESC
